import React from 'react';
import { Card, CardContent, Box, Typography, Stack, LinearProgress, Chip } from '@mui/material';
import response from './response.json';

interface DailyGoal {
  targetWords: number;
  learnedWords: number;
  percentage: number;
}

interface RecentWord {
  word: string;
  meaning: string;
}

interface VocabularyData {
  currentStreak: number;
  dailyGoal: DailyGoal;
  recentWords: RecentWord[];
}

export default function Widget() {
  const vocabularyData = response.data as VocabularyData;
  const { currentStreak, dailyGoal, recentWords } = vocabularyData;
  const { theme, primaryColor, accentColor } = response.meta;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: theme === 'dark' ? '#1C1C1E' : '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ mb: 1, color: primaryColor }}>
              Vocabulary Builder
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Current Streak: {currentStreak} days
            </Typography>
          </Box>

          <Box>
            <Typography variant="body2" color="text.secondary" sx={{ mb: 0.5 }}>
              Daily Goal
            </Typography>
            <Typography variant="h4" fontWeight={700} sx={{ color: primaryColor }}>
              {dailyGoal.learnedWords}/{dailyGoal.targetWords}
            </Typography>
            <LinearProgress
              variant="determinate"
              value={dailyGoal.percentage}
              sx={{
                height: 8,
                borderRadius: 4,
                bgcolor: '#E0E0E0',
                '& .MuiLinearProgress-bar': {
                  bgcolor: accentColor,
                  borderRadius: 4,
                },
              }}
            />
          </Box>

          <Box>
            <Typography variant="body2" color="text.secondary" sx={{ mb: 0.5 }}>
              Recent Words
            </Typography>
            <Stack direction="row" spacing={0.5}>
              {recentWords.map((word) => (
                <Chip
                  key={word.word}
                  label={word.word}
                  sx={{ fontSize: '11px', px: 1, py: 0.5, bgcolor: theme === 'dark' ? '#2C2C2E' : '#F5F5F5', color: primaryColor }}
                />
              ))}
            </Stack>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
